+using Microsoft.Agents.AI;
+using Microsoft.Extensions.AI;
+
+var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
+    ?? throw new InvalidOperationException(
+        "Set the OPENAI_API_KEY environment variable before running this app.");
+
+const string modelId = "gpt-4o-mini-2024-07-18";
+
+IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
+    .GetChatClient(modelId)
+    .AsIChatClient();
+
+var researchTools = new ResearchTools();
+
+var agent = new ChatClientAgent(
+    chatClient,
+    name: "ResearchAgent",
+    instructions: """
+        You are a research assistant. When given a topic:
+        1. Search the web for relevant information using the search tool (make 2-3 searches with different queries).
+        2. Save important findings as notes using the note-taking tool.
+        3. After gathering enough information, produce a well-structured summary of your notes.
+        Always cite your sources. Be thorough but concise.
+        """,
+    tools: [
+        AIFunctionFactory.Create(researchTools.SearchWeb),
+        AIFunctionFactory.Create(researchTools.SaveNote),
+        AIFunctionFactory.Create(researchTools.GetNotes),
+    ]);
+
+Console.Write("Enter a research topic: ");
+var topic = Console.ReadLine()?.Trim();
+if (string.IsNullOrEmpty(topic))
+{
+    Console.WriteLine("No topic provided. Exiting.");
+    return;
+}
+
+Console.WriteLine($"\nResearching: {topic}\n");
+
+var runOptions = new ChatClientAgentRunOptions(new ChatOptions
+{
+    Temperature = 0f,
+    MaxOutputTokens = 2048,
+});
+
+var response = await agent.RunAsync(
+    $"Research the following topic and provide a comprehensive summary: {topic}",
+    session: null,
+    runOptions);
+
+Console.WriteLine("═══ Research Summary ═══\n");
+Console.WriteLine(response.Text);
+
+if (researchTools.Notes.Count > 0)
+{
+    Console.WriteLine($"\n═══ {researchTools.Notes.Count} note(s) saved during research ═══");
+}
+
+/// <summary>
+/// Provides web search and note-taking tools for the research agent.
+/// </summary>
+sealed class ResearchTools
+{
+    private static readonly HttpClient HttpClient = new();
+    private static readonly JsonSerializerOptions JsonOptions = new() { PropertyNameCaseInsensitive = true };
+
+    public List<NoteEntry> Notes { get; } = [];
+
+    [Description("Search the web for information on a query. Returns a list of results with titles, URLs, and snippets.")]
+    public async Task<string> SearchWeb(
+        [Description("The search query to look up")] string query,
+        CancellationToken cancellationToken = default)
+    {
+        Console.WriteLine($"  🔍 Searching: {query}");
+        try
+        {
+            var encoded = Uri.EscapeDataString(query);
+            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
+            var response = await HttpClient.GetFromJsonAsync<DuckDuckGoResponse>(url, JsonOptions, cancellationToken);
+            if (response is null)
+            {
+                return "No results found.";
+            }
+
+            var results = new List<string>();
+
+            if (!string.IsNullOrWhiteSpace(response.Abstract))
+            {
+                results.Add($"**Summary**: {response.Abstract} (Source: {response.AbstractURL})");
+            }
+
+            foreach (var topic in response.RelatedTopics?.Take(5) ?? [])
+            {
+                if (!string.IsNullOrWhiteSpace(topic.Text))
+                {
+                    results.Add($"- {topic.Text} ({topic.FirstURL})");
+                }
+            }
+
+            return results.Count > 0
+                ? string.Join("\n", results)
+                : "No relevant results found. Try a different search query.";
+        }
+        catch (Exception ex)
+        {
+            return $"Search failed: {ex.Message}. Try rephrasing the query.";
+        }
+    }
+
+    [Description("Save a research note with a title and content. Use this to record important findings.")]
+    public string SaveNote(
+        [Description("A short title for the note")] string title,
+        [Description("The content of the note")] string content,
+        [Description("The source URL, if available")] string? source = null)
+    {
+        var note = new NoteEntry(title, content, source);
+        Notes.Add(note);
+        Console.WriteLine($"  📝 Note saved: {title}");
+        return $"Note '{title}' saved successfully (note #{Notes.Count}).";
+    }
+
+    [Description("Retrieve all saved research notes. Use this before writing the final summary.")]
+    public string GetNotes()
+    {
+        if (Notes.Count == 0)
+        {
+            return "No notes saved yet.";
+        }
+
+        var formatted = Notes.Select((n, i) =>
+            $"Note #{i + 1}: {n.Title}\n{n.Content}"
+            + (n.Source is not null ? $"\nSource: {n.Source}" : ""));
+        return string.Join("\n---\n", formatted);
+    }
+}
+
+record NoteEntry(string Title, string Content, string? Source);
+
+record DuckDuckGoResponse(
+    string? Abstract,
+    string? AbstractURL,
+    List<DuckDuckGoTopic>? RelatedTopics);
+
+record DuckDuckGoTopic(string? Text, string? FirstURL);
